@namespace Lumeo

@{
    var context = new ListContext(Bordered, Hoverable, Size);
}

<CascadingValue Value="context" IsFixed="false">
    <ul role="list" class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </ul>
</CascadingValue>

@code {
    /// <summary>One or more <see cref="ListItem"/> elements, rendered inside the <c>&lt;ul&gt;</c>.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Wraps the list in a rounded border and separates items with divider lines.</summary>
    [Parameter] public bool Bordered { get; set; }
    /// <summary>Highlights each <see cref="ListItem"/> on hover. Cascaded to items via <see cref="ListContext"/>.</summary>
    [Parameter] public bool Hoverable { get; set; }
    /// <summary>Controls each <see cref="ListItem"/>'s row padding. Cascaded to items via <see cref="ListContext"/>. Default <see cref="Lumeo.Size.Md"/>.</summary>
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;
    /// <summary>Additional CSS classes merged onto the <c>&lt;ul&gt;</c> element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Captures any unmatched attributes and applies them to the <c>&lt;ul&gt;</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(
        "w-full",
        Cx.When(Bordered, "divide-y divide-border/40 rounded-md border border-border/40"),
        Class);

    public record ListContext(bool Bordered, bool Hoverable, Lumeo.Size Size);

}

@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop

@{
    // Row padding keyed on List Size x ambient DensityScope; Comfortable
    // reproduces the historical per-Size padding verbatim.
    var paddingClass = (Context?.Size ?? Lumeo.Size.Md, Density ?? Lumeo.Density.Comfortable) switch
    {
        (Lumeo.Size.Sm, Lumeo.Density.Compact)  => "px-2.5 py-1.5",
        (Lumeo.Size.Sm, Lumeo.Density.Spacious) => "px-4 py-3",
        (Lumeo.Size.Sm, _)                      => "px-3 py-2",
        (Lumeo.Size.Lg, Lumeo.Density.Compact)  => "px-4 py-3",
        (Lumeo.Size.Lg, Lumeo.Density.Spacious) => "px-6 py-5",
        (Lumeo.Size.Lg, _)                      => "px-5 py-4",
        (_, Lumeo.Density.Compact)              => "px-3 py-2",
        (_, Lumeo.Density.Spacious)             => "px-5 py-4",
        _                                       => "px-4 py-3"
    };
    var hoverClass = Context?.Hoverable == true ? "hover:bg-accent/50 transition-colors" : "";
    var clickableClass = (OnClick.HasDelegate || !string.IsNullOrEmpty(Href)) ? "cursor-pointer" : "";
    var disabledClass = Disabled ? "opacity-50 pointer-events-none" : "";
    var liClass = Cx.Merge("flex items-center gap-3", paddingClass, hoverClass, clickableClass, disabledClass, Class);
}

@if (!string.IsNullOrEmpty(Href))
{
    <li class="@liClass" @attributes="AdditionalAttributes">
        @* OnClick fires alongside navigation — no preventDefault, both work.
           When Disabled, drop the navigable href and pull the anchor out of the
           tab order with aria-disabled so keyboard + AT honour Disabled, not just
           the pointer-events-none class (which only blocks mouse). *@
        <a href="@(Disabled ? null : Href)"
           tabindex="@(Disabled ? "-1" : null)"
           aria-disabled="@(Disabled ? "true" : null)"
           class="flex flex-1 items-center gap-3 min-w-0" @onclick="HandleClick">
            @if (Leading != null)
            {
                <div class="shrink-0">@Leading</div>
            }
            <div class="flex-1 min-w-0">
                @if (Title != null)
                {
                    <p class="text-sm font-medium truncate">@Title</p>
                }
                @if (Description != null)
                {
                    <p class="text-xs text-muted-foreground truncate">@Description</p>
                }
                @ChildContent
            </div>
        </a>
        @if (Trailing != null)
        {
            <div class="shrink-0">@Trailing</div>
        }
    </li>
}
else
{
    <li class="@liClass"
        id="@(OnClick.HasDelegate ? _buttonId : null)"
        role="@(OnClick.HasDelegate ? "button" : null)"
        tabindex="@(OnClick.HasDelegate && !Disabled ? "0" : null)"
        aria-disabled="@(Disabled && OnClick.HasDelegate ? "true" : null)"
        @onclick="HandleClick"
        @onkeydown="HandleKeyDown"
        @attributes="AdditionalAttributes">
        @if (Leading != null)
        {
            <div class="shrink-0">@Leading</div>
        }
        <div class="flex-1 min-w-0">
            @if (Title != null)
            {
                <p class="text-sm font-medium truncate">@Title</p>
            }
            @if (Description != null)
            {
                <p class="text-xs text-muted-foreground truncate">@Description</p>
            }
            @ChildContent
        </div>
        @if (Trailing != null)
        {
            <div class="shrink-0">@Trailing</div>
        }
    </li>
}

@code {
    [CascadingParameter] public List.ListContext? Context { get; set; }
    [CascadingParameter] private Lumeo.Density? Density { get; set; }

    /// <summary>Extra content rendered below <see cref="Title"/>/<see cref="Description"/>, inside the item's main flex-1 column.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Content rendered at the start of the row (e.g. an icon or avatar), before the title/description.</summary>
    [Parameter] public RenderFragment? Leading { get; set; }
    /// <summary>Content rendered at the end of the row (e.g. an action button or chevron), after the title/description.</summary>
    [Parameter] public RenderFragment? Trailing { get; set; }
    /// <summary>Primary text, rendered as a truncating single line above <see cref="Description"/>.</summary>
    [Parameter] public string? Title { get; set; }
    /// <summary>Secondary text, rendered as a truncating single line below <see cref="Title"/>.</summary>
    [Parameter] public string? Description { get; set; }
    /// <summary>When set, renders the item as a navigable <c>&lt;a&gt;</c> pointing at this URL instead of a plain <c>&lt;li&gt;</c>. <see cref="OnClick"/> still fires alongside navigation.</summary>
    [Parameter] public string? Href { get; set; }
    /// <summary>Makes the item clickable/keyboard-activatable (role <c>button</c> when not also an <see cref="Href"/> link) and raised on click, Enter, or Space.</summary>
    [Parameter] public EventCallback OnClick { get; set; }
    /// <summary>Dims the item, removes it from the tab order, and suppresses <see cref="Href"/> navigation and <see cref="OnClick"/>.</summary>
    [Parameter] public bool Disabled { get; set; }
    /// <summary>Additional CSS classes merged onto the <c>&lt;li&gt;</c> element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Captures any unmatched attributes and applies them to the <c>&lt;li&gt;</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Stable id on the role=button <li> so the JS key-suppression handler
    // (RegisterPreventDefaultKeys) has a target to bind to. n=15: a clickable
    // (non-href) ListItem renders as <li role="button">, which has no native key
    // synthesis — pressing Space both activated the item (HandleKeyDown) AND fired
    // the browser's default Space action, scroll-jumping the page. The fix
    // suppresses Space's default action via the library's RegisterPreventDefaultKeys
    // interop (same idiom as InplaceEditor / DialogTrigger), which needs an id.
    private readonly string _buttonId = LumeoIds.New("list-item");
    // Tracks whether the Space-suppression keydown listener is currently bound. The
    // listener only makes sense while this is an activatable button (OnClick set),
    // so we (re-)register/unregister as that condition flips.
    private bool _pdRegistered;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // n=15: bind Space's preventDefault to the live role=button node so Space
        // activates the item without scroll-jumping the page. Only the clickable
        // (non-href) branch is a role=button; the href branch is a native <a> that
        // has no Space default action. Enter has no default action on an <li>, so
        // only Space needs suppression — matching InplaceEditor / DialogTrigger.
        var isButton = OnClick.HasDelegate;
        if (isButton && !_pdRegistered)
        {
            try
            {
                await Interop.RegisterPreventDefaultKeys(
                    _buttonId,
                    new[] { new Lumeo.Services.PreventDefaultKeyRule(" ") });
                _pdRegistered = true;
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
            catch (InvalidOperationException) { } // JS interop unavailable during prerender
        }
        else if (!isButton && _pdRegistered)
        {
            _pdRegistered = false;
            try { await Interop.UnregisterPreventDefaultKeys(_buttonId); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
            catch (InvalidOperationException) { }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_buttonId);
        }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    private async Task HandleClick()
    {
        if (!Disabled && OnClick.HasDelegate)
            await OnClick.InvokeAsync();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (Disabled || !OnClick.HasDelegate) return;
        if (e.Key is "Enter" or " ") await OnClick.InvokeAsync();
    }
}
